from typing import Dict, List

def solve(s: str) -> str:
    VOWELS = {'a', 'e', 'i', 'o', 'u'}

    # Phase 1: Calculate frequencies and find first occurrences
    counts: Dict[str, int] = {}
    first_occurrence: Dict[str, int] = {}
    vowel_indices: List[int] = []

