        if char in VOWELS:
            vowel_indices.append(i)

            # Update count
            counts[char] = counts.get(char, 0) + 1

            # Record first occurrence
            if char not in first_occurrence:
                first_occurrence[char] = i

    if not counts:
        return s

    # Phase 2: Determine the sorted sequence of vowels

    # Get unique vowels present in s
    unique_vowels = list(counts.keys())

    # Sorting criteria: 
