    # 2. First appearance index (ascending)
    def sort_key(v: str):
        return (-counts[v], first_occurrence[v])

    # Sort the unique vowel types
    sorted_vowel_types = sorted(unique_vowels, key=sort_key)

    # Construct the final sorted list of all vowels
    sorted_vowel_sequence: List[str] = []
    for v_type in sorted_vowel_types:
        count = counts[v_type]
        sorted_vowel_sequence.extend([v_type] * count)

