from collections import Counter
from typing import Dict, List

def solve(s: str) -> str:
    """
    Rearranges only the vowels in string s based on frequency (non-increasing)
    and then by first appearance position (ascending) as a tie-breaker.
    """
    VOWELS = {'a', 'e', 'i', 'o', 'u'}

    # 1. Identify and count vowels, record first appearance
    vowel_counts = Counter()
    first_appearance: Dict[str, int] = {}

    for i, char in enumerate(s):
        if char in VOWELS:
            vowel_counts[char] += 1
            if char not in first_appearance:
                first_appearance[char] = i

    # 2. Determine the sorted order of unique vowels
    unique_vowels = list(vowel_counts.keys())

    # Sort criteria: 
    # Primary: Frequency (Descending, hence the negative sign)
    # Secondary: First appearance index (Ascending)
    def sort_key(vowel: str) -> tuple[int, int]:
        return (-vowel_counts[vowel], first_appearance[vowel])

    sorted_unique_vowels: List[str] = sorted(unique_vowels, key=sort_key)

    # 3. Generate the final sequence of all vowels
    ordered_vowel_sequence: List[str] = []
    for v in sorted_unique_vowels:
        ordered_vowel_sequence.extend([v] * vowel_counts[v])

    # 4. Rebuild the string
    result_list: List[str] = list(s)
    vowel_idx = 0

    for i in range(len(s)):
        if s[i] in VOWELS:
            # Replace the vowel at this position with the next vowel from the sorted sequence
            result_list[i] = ordered_vowel_sequence[vowel_idx]
            vowel_idx += 1

    return "".join(result_list)
